request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?modelNormId ?modelOrigId ?orgId ?created ?choreoName ?taskName WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  ?choreo bbo:name ?choreoName ;
          tai:belongsTo ?defs .

  ?defs tai:belongsTo ?model .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:organizationId ?orgId ;
         tai:normalizedId ?modelNormId .
  OPTIONAL { ?model tai:originalId ?modelOrigId . }
  OPTIONAL { ?model tai:modelCreated ?created . }

  FILTER(
    (CONTAINS(LCASE(STR(?taskName)), LCASE("take order")) || CONTAINS(LCASE(STR(?taskName)), LCASE("send order")) || CONTAINS(LCASE(STR(?taskName)), LCASE("estimate the delivery time")))
    && CONTAINS(LCASE(STR(?taskName)), LCASE("restaurant"))
  )
}
ORDER BY ?modelName ?choreoName
LIMIT 25
